from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subjects = {}
    for triple in triples:
        if triple.subject not in subjects:
            subjects[triple.subject] = []
        subjects[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject in subjects:
        subject_sentence = f"{subject} "
        for i, (predicate, object) in enumerate(subjects[subject]):
            if predicate == "cityServed":
                subject_sentence += f"serves the city of {object}"
            elif predicate == "location":
                subject_sentence += f"located in {object}"
            elif predicate == "operatingOrganisation":
                subject_sentence += f"operated by {object}"
            elif predicate == "elevationAboveTheSeaLevel":
                subject_sentence += f"with an elevation of {object} meters"
            elif predicate == "runwayLength":
                subject_sentence += f"with a runway length of {object} meters"
            elif predicate == "runwayName":
                subject_sentence += f"with a runway named {object}"
            elif predicate == "country":
                subject_sentence += f"located in the country of {object}"
            elif predicate == "isPartOf":
                subject_sentence += f"part of {object}"
            elif predicate == "mayor":
                subject_sentence += f"where the mayor is {object}"
            if i < len(subjects[subject]) - 1:
                subject_sentence += ", "
        sentence += subject_sentence + ". "

    # Connect sentences with "which is" or "where"
    connected_sentence = ""
    for i, subject in enumerate(subjects):
        subject_sentence = sentence.split(".")[i]
        if i > 0:
            if "country" in subject_sentence:
                connected_sentence += " which is " + subject_sentence
            else:
                connected_sentence += " where " + subject_sentence
        else:
            connected_sentence += subject_sentence
    return connected_sentence + "."

